from functools import wraps

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, ConnectionError, TransportError

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

# Configuration
ES_HOST = os.environ.get("ELASTICSEARCH_HOST", "localhost")
ES_PORT = int(os.environ.get("ELASTICSEARCH_PORT", 9200))
ES_INDEX = os.environ.get("ELASTICSEARCH_INDEX", "products")
ES_USERNAME = os.environ.get("ELASTICSEARCH_USERNAME", "")
ES_PASSWORD = os.environ.get("ELASTICSEARCH_PASSWORD", "")

# Rate limiting configuration
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 100  # max requests per window per IP

# Simple in-memory rate limiter (use Redis in production)
rate_limit_store = {}


def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    es_kwargs = {
        "hosts": [{"host": ES_HOST, "port": ES_PORT}],
        "maxsize": 25,  # Connection pool size for high traffic
        "retry_on_timeout": True,
        "max_retries": 3,
        "timeout": 10,
        "sniff_on_start": False,
        "sniff_on_connection_fail": False,
    }

    if ES_USERNAME and ES_PASSWORD:
        es_kwargs["http_auth"] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**es_kwargs)


es_client = get_es_client()


def check_rate_limit(ip_address):
    """Simple in-memory rate limiter. Replace with Redis-based solution for production."""
    now = time.time()
    window_start = now - RATE_LIMIT_WINDOW

    if ip_address not in rate_limit_store:
        rate_limit_store[ip_address] = []

    # Remove old entries
    rate_limit_store[ip_address] = [
        t for t in rate_limit_store[ip_address] if t > window_start
    ]

    if len(rate_limit_store[ip_address]) >= RATE_LIMIT_MAX_REQUESTS:
        return False

    rate_limit_store[ip_address].append(now)
    return True


def rate_limit(f):
    """Rate limiting decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.headers.get("X-Forwarded-For", request.remote_addr)
        if not check_rate_limit(client_ip):
            return jsonify({
                "error": "Rate limit exceeded",
                "message": f"Maximum {RATE_LIMIT_MAX_REQUESTS} requests per {RATE_LIMIT_WINDOW} seconds",
            }), 429
        return f(*args, **kwargs)
    return decorated_function


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       sort_by=None, sort_order="desc"):
    """Build an Elasticsearch query with optional filters."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search using multi_match for broad matching
    must_clauses.append({
        "multi_match": {
            "query": keyword,
            "fields": [
                "name^3",          # Boost product name matches
                "name.autocomplete^2",
                "description^1.5",
                "category^1",
                "brand^2",
                "tags^1",
            ],
            "type": "best_fields",
            "fuzziness": "AUTO",
            "prefix_length": 2,
            "minimum_should_match": "75%",
        }
    })

    # Optional category filter
    if category:
        filter_clauses.append({
            "term": {"category.keyword": category}
        })

    # Optional price range filter
    price_range = {}
    if min_price is not None:
        price_range["gte"] = float(min_price)
    if max_price is not None:
        price_range["lte"] = float(max_price)
    if price_range:
        filter_clauses.append({
            "range": {"price": price_range}
        })

    # Only show active/in-stock products
    filter_clauses.append({
        "term": {"is_active": True}
    })

    query = {
        "bool": {
            "must": must_clauses,
            "filter": filter_clauses,
        }
    }

    # Build sort
    sort = []
    if sort_by:
        if sort_by in ("price", "rating", "created_at", "popularity"):
            sort.append({sort_by: {"order": sort_order}})
    # Always include relevance score as secondary sort
    sort.append("_score")

    return query, sort


def build_aggregations():
    """Build aggregations for faceted search."""
    return {
        "categories": {
            "terms": {
                "field": "category.keyword",
                "size": 20,
            }
        },
        "brands": {
            "terms": {
                "field": "brand.keyword",
                "size": 20,
            }
        },
        "price_ranges": {
            "range": {
                "field": "price",
                "ranges": [
                    {"key": "under_25", "to": 25},
                    {"key": "25_to_50", "from": 25, "to": 50},
                    {"key": "50_to_100", "from": 50, "to": 100},
                    {"key": "100_to_200", "from": 100, "to": 200},
                    {"key": "over_200", "from": 200},
                ]
            }
        },
        "avg_price": {
            "avg": {
                "field": "price"
            }
        },
    }


def format_search_results(es_response, page, page_size):
    """Format Elasticsearch response into a clean API response."""
    hits = es_response.get("hits", {})
    total = hits.get("total", {})

    # Handle both ES 6.x and 7.x total format
    if isinstance(total, dict):
        total_count = total.get("value", 0)
    else:
        total_count = total

    products = []
    for hit in hits.get("hits", []):
        product = hit.get("_source", {})
        product["id"] = hit.get("_id")
        product["_score"] = hit.get("_score")

        # Include highlights if available
        if "highlight" in hit:
            product["highlights"] = hit["highlight"]

        products.append(product)

    # Format aggregations
    aggregations = {}
    raw_aggs = es_response.get("aggregations", {})
    for agg_name, agg_data in raw_aggs.items():
        if "buckets" in agg_data:
            aggregations[agg_name] = [
                {"key": bucket["key"], "count": bucket["doc_count"]}
                for bucket in agg_data["buckets"]
            ]
        elif "value" in agg_data:
            aggregations[agg_name] = agg_data["value"]

    total_pages = (total_count + page_size - 1) // page_size if page_size > 0 else 0

    return {
        "results": products,
        "pagination": {
            "total": total_count,
            "page": page,
            "page_size": page_size,
            "total_pages": total_pages,
            "has_next": page < total_pages,
            "has_prev": page > 1,
        },
        "facets": aggregations,
    }


@app.route("/api/search", methods=["GET"])
@rate_limit
def search_products():
    """
    Search products by keyword.

    Query Parameters:
        q (str, required): Search keyword
        page (int, optional): Page number (default: 1)
        page_size (int, optional): Results per page (default: 20, max: 100)
        category (str, optional): Filter by category
        min_price (float, optional): Minimum price filter
        max_price (float, optional): Maximum price filter
        sort_by (str, optional): Sort field (price, rating, created_at, popularity)
        sort_order (str, optional): Sort order (asc, desc; default: desc)
        include_facets (bool, optional): Include aggregation facets (default: true)
    """
    start_time = time.time()

    # Extract and validate query parameters
    keyword = request.args.get("q", "").strip()
    if not keyword:
        return jsonify({
            "error": "Missing required parameter",
            "message": "Query parameter 'q' is required",
        }), 400

    if len(keyword) > 200:
        return jsonify({
            "error": "Invalid parameter",
            "message": "Query parameter 'q' must be 200 characters or fewer",
        }), 400

    # Pagination
    try:
        page = max(1, int(request.args.get("page", 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(100, max(1, int(request.args.get("page_size", 20))))
    except (ValueError, TypeError):
        page_size = 20

    # Filters
    category = request.args.get("category", "").strip() or None

    min_price = request.args.get("min_price")
    max_price = request.args.get("max_price")

    try:
        if min_price is not None:
            min_price = float(min_price)
            if min_price < 0:
                return jsonify({
                    "error": "Invalid parameter",
                    "message": "min_price must be non-negative",
                }), 400
    except (ValueError, TypeError):
        return jsonify({
            "error": "Invalid parameter",
            "message": "min_price must be a valid number",
        }), 400

    try:
        if max_price is not None:
            max_price = float(max_price)
            if max_price < 0:
                return jsonify({
                    "error": "Invalid parameter",
                    "message": "max_price must be non-negative",
                }), 400
    except (ValueError, TypeError):
        return jsonify({
            "error": "Invalid parameter",
            "message": "max_price must be a valid number",
        }), 400

    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({
            "error": "Invalid parameter",
            "message": "min_price must be less than or equal to max_price",
        }), 400

    # Sort
    sort_by = request.args.get("sort_by")
    sort_order = request.args.get("sort_order", "desc").lower()
    if sort_order not in ("asc", "desc"):
        sort_order = "desc"

    # Facets
    include_facets = request.args.get("include_facets", "true").lower() != "false"

    # Build the search query
    query, sort = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        sort_by=sort_by,
        sort_order=sort_order,
    )

    # Build the full search body
    from_offset = (page - 1) * page_size

    search_body = {
        "query": query,
        "sort": sort,
        "from": from_offset,
        "size": page_size,
        "highlight": {
            "fields": {
                "name": {"number_of_fragments": 1},
                "description": {"number_of_fragments": 2, "fragment_size": 150},
            },
            "pre_tags": ["<em>"],
            "post_tags": ["</em>"],
        },
        "_source": {
            "excludes": ["embedding"]  # Exclude large vector fields if any
        },
        "track_total_hits": True,
    }

    if include_facets:
        search_body["aggs"] = build_aggregations()

    # Execute search
    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_timeout=5,  # Strict timeout for high traffic
        )
    except ConnectionError as e:
        logger.error(f"Elasticsearch connection error: {e}")
        return jsonify({
            "error": "Service unavailable",
            "message": "Search service is temporarily unavailable. Please try again later.",
        }), 503
    except TransportError as e:
        logger.error(f"Elasticsearch transport error: {e}")
        if e.status_code == 408 or "timeout" in str(e).lower():
            return jsonify({
                "error": "Request timeout",
                "message": "Search request timed out. Please try a more specific query.",
            }), 504
        return jsonify({
            "error": "Search error",
            "message": "An error occurred while processing your search.",
        }), 500
    except Exception as e:
        logger.error(f"Unexpected search error: {e}", exc_info=True)
        return jsonify({
            "error": "Internal server error",
            "message": "An unexpected error occurred.",
        }), 500

    # Format results
    result = format_search_results(es_response, page, page_size)

    # Add metadata
    elapsed_ms = round((time.time() - start_time) * 1000, 2)
    result["meta"] = {
        "query": keyword,
        "took_ms": elapsed_ms,
        "es_took_ms": es_response.get("took", 0),
    }

    response = jsonify(result)

    # Cache headers for high traffic handling
    # Cache search results briefly (CDN-friendly)
    response.headers["Cache-Control"] = "public, max-age=30, s-maxage=60"
    response.headers["Vary"] = "Accept-Encoding"
    response.headers["X-Response-Time"] = f"{elapsed_ms}ms"

    return response, 200


@app.route("/api/search/suggest", methods=["GET"])
@rate_limit
def search_suggestions():
    """
    Get search suggestions/autocomplete for a partial query.

    Query Parameters:
        q (str, required): Partial search query
        size (int, optional): Number of suggestions (default: 5, max: 10)
    """
    keyword = request.args.get("q", "").strip()
    if not keyword or len(keyword) < 2:
        return jsonify({"suggestions": []}), 200

    try:
        size = min(10, max(1, int(request.args.get("size", 5))))
    except (ValueError, TypeError):
        size = 5

    suggest_body = {
        "suggest": {
            "product_suggest": {
                "prefix": keyword,
                "completion": {
                    "field": "name.suggest",
                    "size": size,
                    "skip_duplicates": True,
                    "fuzzy": {
                        "fuzziness": "AUTO",
                    }
                }
            }
        },
        "_source": ["name", "category", "brand"],
    }

    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=suggest_body,
            request_timeout=3,
        )

        suggestions = []
        suggest_results = es_response.get("suggest", {}).get("product_suggest", [])
        for suggest in suggest_results:
            for option in suggest.get("options", []):
                suggestions.append({
                    "text": option.get("text", ""),
                    "score": option.get("_score", 0),
                    "source": option.get("_source", {}),
                })

        response = jsonify({"suggestions": suggestions})
        response.headers["Cache-Control"] = "public, max-age=60, s-maxage=120"
        return response, 200

    except Exception as e:
        logger.error(f"Suggestion error: {e}")
        return jsonify({"suggestions": []}), 200


@app.route("/api/health", methods=["GET"])
def health_check():
    """Health check endpoint for load balancers."""
    try:
        es_health = es_client.cluster.health(request_timeout=3)
        es_status = es_health.get("status", "unknown")
        es_healthy = es_status in ("green", "yellow")
    except Exception as e:
        logger.error(f"Health check failed: {e}")
        es_healthy = False
        es_status = "unreachable"

    status_code = 200 if es_healthy else 503
    return jsonify({
        "status": "healthy" if es_healthy else "unhealthy",
        "elasticsearch": {
            "status": es_status,
            "connected": es_healthy,
        },
    }), status_code


def create_index_if_not_exists():
    """Create the products index with optimized mappings if it doesn't exist."""
    if es_client.indices.exists(index=ES_INDEX):
        logger.info(f"Index '{ES_INDEX}' already exists")
        return

    index_settings = {
        "settings": {
            "number_of_shards": 3,
            "number_of_replicas": 1,
            "refresh_interval": "1s",
            "analysis": {
                "analyzer": {
                    "autocomplete_analyzer": {
                        "type": "custom",
                        "tokenizer": "autocomplete_tokenizer",
                        "filter": ["lowercase"],
                    },
                    "search_analyzer": {
                        "type": "custom",
                        "tokenizer": "standard",
                        "filter": ["lowercase", "synonym_filter"],
                    },
                },
                "tokenizer": {
                    "autocomplete_tokenizer": {
                        "type": "edge_ngram",
                        "min_gram": 2,
                        "max_gram": 20,
                        "token_chars": ["letter", "digit"],
                    }
                },
                "filter": {
                    "synonym_filter": {
                        "type": "synonym",
                        "lenient": True,
                        "synonyms": [
                            "phone, mobile, cellphone, smartphone",
                            "laptop, notebook, computer",
                            "tv, television, monitor, display",
                            "headphones, earphones, earbuds",
                        ]
                    }
                }
            }
        },
        "mappings": {
            "properties": {
                "name": {
                    "type": "text",
                    "analyzer": "standard",
                    "fields": {
                        "keyword": {"type": "keyword"},
                        "autocomplete": {
                            "type": "text",
                            "analyzer": "autocomplete_analyzer",
                            "search_analyzer": "standard",
                        },
                        "suggest": {
                            "type": "completion",
                        },
                    }
                },
                "description": {
                    "type": "text",
                    "analyzer": "standard",
                },
                "category": {
                    "type": "text",
                    "fields": {
                        "keyword": {"type": "keyword"},
                    }
                },
                "brand": {
                    "type": "text",
                    "fields": {
                        "keyword": {"type": "keyword"},
                    }
                },
                "price": {"type": "float"},
                "rating": {"type": "float"},
                "tags": {
                    "type": "text",
                    "fields": {
                        "keyword": {"type": "keyword"},
                    }
                },
                "image_url": {"type": "keyword", "index": False},
                "sku": {"type": "keyword"},
                "is_active": {"type": "boolean"},
                "stock_quantity": {"type": "integer"},
                "popularity": {"type": "integer"},
                "created_at": {"type": "date"},
                "updated_at": {"type": "date"},
            }
        }
    }

    try:
        es_client.indices.create(index=ES_INDEX, body=index_settings)
        logger.info(f"Created index '{ES_INDEX}' with mappings")
    except Exception as e:
        logger.error(f"Failed to create index: {e}")


